document.addEventListener("DOMContentLoaded",(()=>{const e=document.getElementById("wcf-install-pro-elementor");e&&e.addEventListener("click",(async t=>{t.preventDefault(),e.textContent="Installing...",e.disabled=!0;try{const n=await fetch(wcfelementorAjax.ajax_url,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:new URLSearchParams({action:"wcf_pro_install_elementor_plugin",_ajax_nonce:wcfelementorAjax.nonce,slug:t.target.getAttribute("slug"),name:t.target.getAttribute("name")})}),a=await n.json();if(!a.success)throw new Error(a.data.message||"Installation failed.");e.textContent="Elementor Installed & Activated",window.location.reload()}catch(t){e.textContent="Failed to Install",e.disabled=!1,alert(t.message)}}))}));